text:
{
  "formal_minutes": {
    "meeting_meta": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과하는 경우 공개 릴리스 목표는 금요일 15:00 KST이다.",
        "certainty": "confirmed"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "topic": "smoke-theme-pack.mjs 처리 방식",
        "proposal": "packageName mismatch를 무시하도록 smoke-theme-pack.mjs를 변경하자는 제안",
        "result": "rejected"
      }
    ],
    "internal_stretch_goals": [
      {
        "topic": "수요일 릴리스 제안",
        "detail": "수요일 릴리스는 내부 스트레치 목표일 뿐 확정 일정이 아니다.",
        "certainty": "confirmed_as_non_final"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "detail": "목요일까지 가능하면 검토하자는 의견이 있었으나 담당자는 지정되지 않았다."
      },
      {
        "topic": "수요일 스트레치 목표의 릴리스 노트 기재 여부",
        "detail": "언급 여부에 대한 결론이 나지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래된 상태라면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "미지정",
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일(가능하면)",
      "status": "suggested_without_owner",
      "source_certainty": "explicit"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 재실행 결과가 실제로 공유되었는지 확인한다.",
      "스모크 통과 여부를 기준으로 금요일 15:00 KST 공개 릴리스 목표 유지 가능성을 점검한다.",
      "Hara의 tarball 경로 확인 결과를 받아 경로 오류 리스크를 해소했는지 확인한다.",
      "Doyun의 실패 트리아지 노트가 action_items.md에 반영되었는지 확인한다.",
      "README 설치 절차 검토의 담당자 지정 필요 여부를 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트 기재 범위를 후속 논의 안건으로 올린다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "미지정 담당자",
      "명시되지 않은 마감 시한"
    ]
  },
  "non_invention_rules": [
    "고객, 외부 파트너, 예산, 보안, 장애, 법무 관련 사실은 회의 기록에 없는 한 추가하지 않는다.",
    "담당자와 마감은 명시된 경우에만 기록하고, 없으면 미지정 또는 미정으로 둔다.",
    "수요일 릴리스는 확정 일정이 아니라 내부 스트레치 목표로만 기록한다.",
    "거절된 제안과 확정된 결정은 분리해 기록한다.",
    "공개 릴리스 조건은 스모크 테스트 통과라는 전제를 유지한다."
  ]
}
